package com.facilcomanda.restaurantservice.entity; import jakarta.persistence.*; @Entity @Table(name="restaurant_floors", indexes=@Index(name="idx_floor_org", columnList="organization_id")) public class RestaurantFloor { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(name="organization_id") private Long organizationId; private String name; private String description; public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getOrganizationId(){return organizationId;} public void setOrganizationId(Long organizationId){this.organizationId=organizationId;} public String getName(){return name;} public void setName(String name){this.name=name;} public String getDescription(){return description;} public void setDescription(String description){this.description=description;} }
